mapper.select:
SELECT * FROM t_house


    AND status = 'ON'

        AND (name LIKE CONCAT('%', #{query.keyword}, '%')
             OR city LIKE CONCAT('%', #{query.keyword}, '%')
             OR facilities LIKE CONCAT('%', #{query.keyword}, '%'))


        AND city = #{query.city}


        AND type = #{query.type}


        AND price >= #{query.minPrice}


        AND price <= #{query.maxPrice}


        AND capacity >= #{query.guests}



        AND id NOT IN (
            SELECT house_id FROM t_availability
            WHERE date >= #{query.checkIn} AND date < #{query.checkOut}
        )

        AND id NOT IN (
            SELECT house_id FROM t_order
            WHERE status NOT IN ('CANCELLED', 'REFUNDED')
              AND check_in < #{query.checkOut}
              AND check_out > #{query.checkIn}
        )




        ORDER BY price ASC


        ORDER BY price DESC


        ORDER BY rating DESC


        ORDER BY sales DESC


        ORDER BY create_time DESC
